<?php header('Access-Control-Allow-Origin: *'); header('Access-Control-Allow-Methods: GET, OPTIONS'); header('Content-Type: application/json'); if ($_SERVER['REQUEST_METHOD'] === 'OPTIONS') { exit; } $host = 'localhost'; $db = 'Guardian'; $user = 'root'; $pass = ''; try { $pdo = new PDO("mysql:host=$host;dbname=$db;charset=utf8mb4", $user, $pass, [PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION, PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC]); $uri = parse_url($_SERVER['REQUEST_URI'], PHP_URL_PATH); $parts = explode('/', trim($uri, '/')); if ($parts[0] === 'api' && $parts[1] === 'vips' && !isset($parts[2])) { $stmt = $pdo->query("SELECT * FROM vips"); echo json_encode($stmt->fetchAll()); } elseif ($parts[0] === 'api' && $parts[1] === 'vips' && isset($parts[2]) && isset($parts[3]) && $parts[3] === 'funcionarios') { $stmt = $pdo->prepare("SELECT * FROM funcionarios WHERE vip_id = ?"); $stmt->execute([$parts[2]]); echo json_encode($stmt->fetchAll()); } elseif ($parts[0] === 'api' && $parts[1] === 'organograma' && isset($parts[2])) { $stmt = $pdo->prepare("SELECT * FROM vips WHERE id = ?"); $stmt->execute([$parts[2]]); $vip = $stmt->fetch(); if (!$vip) { http_response_code(404); echo json_encode(['error' => 'VIP not found']); exit; } $stmt = $pdo->prepare("SELECT * FROM funcionarios WHERE vip_id = ?"); $stmt->execute([$parts[2]]); $vip['funcionarios'] = $stmt->fetchAll(); echo json_encode($vip); } else { http_response_code(404); echo json_encode(['error' => 'Endpoint not found']); } } catch (Exception $e) { http_response_code(500); echo json_encode(['error' => $e->getMessage()]); }